@page "/apply"
@rendermode InteractiveServer
@using sv_dd1710e94aac4186a18cd177494cf1a1.Models
@using sv_dd1710e94aac4186a18cd177494cf1a1.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<h1 class="mb-4">Job Application</h1>

<StepIndicator CurrentStep="currentStep"
               CompletedSteps="completedSteps"
               OnStepClicked="GoToStep" />

<div class="mt-4">
    @if (submitted)
    {
        <div class="alert alert-success text-center py-5">
            <h2>✅ Application Submitted!</h2>
            <p class="lead mt-3">Your application has been received.</p>
            <p class="fs-4">Application ID: <strong>@applicationId</strong></p>
        </div>
    }
    else
    {
        @switch (currentStep)
        {
            case 1:
                <StepPersonalInfo FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                                  FullNameChanged="v => fullName = v"
                                  EmailChanged="v => email = v"
                                  PhoneChanged="v => phone = v"
                                  AddressChanged="v => address = v"
                                  OnNext="HandlePersonalInfoNext"
                                  ValidationError="@validationError"
                                  IsValidating="@isValidating" />
                break;
            case 2:
                <StepWorkHistory WorkEntries="@workEntries"
                                 OnBack="() => GoToStep(1)"
                                 OnNext="HandleWorkHistoryNext"
                                 ValidationError="@validationError" />
                break;
            case 3:
                <StepReferences References="@references"
                                OnBack="() => GoToStep(2)"
                                OnNext="HandleReferencesNext"
                                ValidationError="@validationError" />
                break;
            case 4:
                <StepCoverLetter @bind-CoverLetter="coverLetter"
                                 MaxLength="2000"
                                 OnBack="() => GoToStep(3)"
                                 OnNext="HandleCoverLetterNext"
                                 ValidationError="@validationError" />
                break;
            case 5:
                <StepReview FullName="@fullName" Email="@email" Phone="@phone" Address="@address"
                            WorkEntries="@workEntries" References="@references" CoverLetter="@coverLetter"
                            OnEditStep="GoToStep"
                            OnSubmit="HandleSubmit"
                            OnBack="() => GoToStep(4)"
                            IsSubmitting="@isSubmitting"
                            SubmitError="@submitError" />
                break;
        }
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    // Step 1
    private string fullName = "";
    private string email = "";
    private string phone = "";
    private string address = "";

    // Step 2
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };

    // Step 3
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4
    private string coverLetter = "";

    // State
    private string? validationError;
    private bool isValidating;
    private bool isSubmitting;
    private string? submitError;
    private bool submitted;
    private int applicationId;

    private void GoToStep(int step)
    {
        if (step < currentStep || completedSteps.Contains(step))
        {
            validationError = null;
            currentStep = step;
        }
    }

    private async Task HandlePersonalInfoNext()
    {
        validationError = null;

        if (string.IsNullOrWhiteSpace(fullName))
        { validationError = "Full name is required."; return; }
        if (string.IsNullOrWhiteSpace(email))
        { validationError = "Email is required."; return; }
        if (string.IsNullOrWhiteSpace(phone))
        { validationError = "Phone is required."; return; }
        if (string.IsNullOrWhiteSpace(address))
        { validationError = "Address is required."; return; }

        isValidating = true;
        StateHasChanged();

        var emailValid = await ApplicationService.ValidateEmailAsync(email);
        isValidating = false;

        if (!emailValid)
        { validationError = "Please enter a valid email address."; return; }

        completedSteps.Add(1);
        currentStep = 2;
    }

    private void HandleWorkHistoryNext()
    {
        validationError = null;

        foreach (var entry in workEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                validationError = "Each work entry must have a company name and job title.";
                return;
            }
            if (entry.StartDate == default)
            {
                validationError = "Each work entry must have a start date.";
                return;
            }
        }

        completedSteps.Add(2);
        currentStep = 3;
    }

    private void HandleReferencesNext()
    {
        validationError = null;

        foreach (var r in references)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Email))
            {
                validationError = "Each reference must have a name and email.";
                return;
            }
        }

        completedSteps.Add(3);
        currentStep = 4;
    }

    private void HandleCoverLetterNext()
    {
        validationError = null;

        if (string.IsNullOrWhiteSpace(coverLetter))
        { validationError = "Cover letter is required."; return; }
        if (coverLetter.Length > 2000)
        { validationError = "Cover letter must be 2000 characters or fewer."; return; }

        completedSteps.Add(4);
        currentStep = 5;
    }

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;
        StateHasChanged();

        try
        {
            var application = new JobApplication(
                new PersonalInfo(fullName, email, phone, address),
                new WorkHistory(workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description
                )).ToList()),
                references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                coverLetter
            );

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            completedSteps.Add(5);
            submitted = true;
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }

    public class ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

