@{
    var stepNames = new[] { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
}

<nav aria-label="Application steps">
    <ol class="d-flex list-unstyled justify-content-between step-indicator mb-0">
        @for (int i = 0; i < stepNames.Length; i++)
        {
            var stepNumber = i + 1;
            var isCompleted = CompletedSteps.Contains(stepNumber);
            var isCurrent = stepNumber == CurrentStep;
            var isClickable = isCompleted && !isCurrent;

            <li class="text-center flex-fill @(isCurrent ? "step-current" : isCompleted ? "step-completed" : "step-future")"
                role="listitem">
                @if (isClickable)
                {
                    <a href="" @onclick="() => OnStepClicked.InvokeAsync(stepNumber)" @onclick:preventDefault
                       class="text-decoration-none">
                        <span class="step-circle">✔</span>
                        <span class="d-block small mt-1">@stepNames[i]</span>
                    </a>
                }
                else
                {
                    <span>
                        <span class="step-circle">@(isCompleted ? "✔" : stepNumber.ToString())</span>
                        <span class="d-block small mt-1">@stepNames[i]</span>
                    </span>
                }
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

