.step-indicator li {
    position: relative;
}

.step-indicator li + li::before {
    content: "";
    position: absolute;
    top: 16px;
    left: -50%;
    right: 50%;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step-indicator li.step-completed + li::before {
    background: #198754;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 34px;
    height: 34px;
    border-radius: 50%;
    font-weight: 600;
    font-size: 0.85rem;
    position: relative;
    z-index: 1;
}

.step-current .step-circle {
    background: #0d6efd;
    color: #fff;
}

.step-completed .step-circle {
    background: #198754;
    color: #fff;
}

.step-future .step-circle {
    background: #dee2e6;
    color: #6c757d;
}

.step-future {
    opacity: 0.5;
}

