toolArgs.file_text:
@using static sv_dd1710e94aac4186a18cd177494cf1a1.Components.Pages.Apply.Apply

<h3>Work History</h3>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger">@ValidationError</div>
}

@for (int i = 0; i < WorkEntries.Count; i++)
{
    var index = i;
    var entry = WorkEntries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h5 class="card-title mb-0">Position @(index + 1)</h5>
                @if (WorkEntries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="entry.Company" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="entry.Title" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-4 mb-3">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control" @bind="entry.StartDate" />
                </div>
                <div class="col-md-4 mb-3">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" @bind="entry.EndDate" disabled="@entry.IsCurrent" />
                </div>
                <div class="col-md-4 mb-3 d-flex align-items-end">
                    <div class="form-check">
                        <input type="checkbox" class="form-check-input" id="current-@index" @bind="entry.IsCurrent" />
                        <label class="form-check-label" for="current-@index">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" @bind="entry.Description"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">+ Add Another Position</button>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public string? ValidationError { get; set; }

    private void AddEntry() => WorkEntries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (WorkEntries.Count > 1)
            WorkEntries.RemoveAt(index);
    }
}

@using static sv_dd1710e94aac4186a18cd177494cf1a1.Components.Pages.Apply.Apply

<h3>References</h3>

@if (!string.IsNullOrEmpty(ValidationError))
{
    <div class="alert alert-danger">@ValidationError</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h5 class="card-title mb-0">Reference @(index + 1)</h5>
                @if (References.Count > 2)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control" @bind="reference.Name" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Relationship</label>
                    <input type="text" class="form-control" @bind="reference.Relationship" />
                </div>
            </div>

            <div class="row">
                <div class="col-md-6 mb-3">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control" @bind="reference.Email" />
                </div>
                <div class="col-md-6 mb-3">
                    <label class="form-label">Phone</label>
                    <input type="tel" class="form-control" @bind="reference.Phone" />
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next →</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public string? ValidationError { get; set; }

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }
}

@using static sv_dd1710e94aac4186a18cd177494cf1a1.Components.Pages.Apply.Apply

<h3>Review & Submit</h3>

@if (!string.IsNullOrEmpty(SubmitError))
{
    <div class="alert alert-danger">@SubmitError</div>
}

<!-- Personal Info -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <a href="" @onclick="() => OnEditStep.InvokeAsync(1)" @onclick:preventDefault>Edit</a>
    </div>
    <div class="card-body">
        <dl class="row mb-0">
            <dt class="col-sm-3">Full Name</dt>
            <dd class="col-sm-9">@FullName</dd>
            <dt class="col-sm-3">Email</dt>
            <dd class="col-sm-9">@Email</dd>
            <dt class="col-sm-3">Phone</dt>
            <dd class="col-sm-9">@Phone</dd>
            <dt class="col-sm-3">Address</dt>
            <dd class="col-sm-9">@Address</dd>
        </dl>
    </div>
</div>

<!-- Work History -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <a href="" @onclick="() => OnEditStep.InvokeAsync(2)" @onclick:preventDefault>Edit</a>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3 pb-3 border-bottom last-child-no-border">
                <h6>@entry.Title at @entry.Company</h6>
                <p class="text-muted mb-1">
                    @entry.StartDate.ToString("MMM yyyy") –
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                </p>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <p class="mb-0">@entry.Description</p>
                }
            </div>
        }
    </div>
</div>

<!-- References -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <a href="" @onclick="() => OnEditStep.InvokeAsync(3)" @onclick:preventDefault>Edit</a>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong>
                @if (!string.IsNullOrWhiteSpace(r.Relationship))
                {
                    <span class="text-muted">(@r.Relationship)</span>
                }
                <br />
                <small>@r.Email @(!string.IsNullOrWhiteSpace(r.Phone) ? $"• {r.Phone}" : "")</small>
            </div>
        }
    </div>
</div>

<!-- Cover Letter -->
<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <a href="" @onclick="() => OnEditStep.InvokeAsync(4)" @onclick:preventDefault>Edit</a>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">← Back</button>
    <button class="btn btn-success btn-lg" @onclick="OnSubmit" disabled="@IsSubmitting">
        @if (IsSubmitting)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Submitting…</span>
        }
        else
        {
            <span>Submit Application</span>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = new();
    [Parameter] public List<ReferenceModel> References { get; set; } = new();
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public string? SubmitError { get; set; }
}

arguments.new_str:
    [Parameter] public bool IsValidating { get; set; }

    private Task HandleFullNameInput(ChangeEventArgs e) => FullNameChanged.InvokeAsync(e.Value?.ToString() ?? "");
